#!/bin/bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-04-25

# Unit test for src/skills/doctor/scripts/check-mcp-pinning.sh
#
# Mocks .mcp.json with mixed pinned/unpinned entries and asserts the script
# emits the correct warnings + exit codes per HIGH/MEDIUM/LOW tier.
# Closes #1462.

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
REPO_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"
CHECK="$REPO_ROOT/src/skills/doctor/scripts/check-mcp-pinning.sh"

if [[ ! -x "$CHECK" ]]; then
    echo "FAIL: $CHECK not found or not executable" >&2
    exit 1
fi

TMP="$(mktemp -d)"
trap 'rm -rf "$TMP"' EXIT

PASS=0
FAIL=0

assert_exit() {
    local name="$1" expected="$2" actual="$3"
    if [[ "$expected" -eq "$actual" ]]; then
        echo "  ✓ $name (exit=$actual)"
        PASS=$((PASS + 1))
    else
        echo "  ✗ $name (expected exit=$expected, got $actual)"
        FAIL=$((FAIL + 1))
    fi
}

assert_contains() {
    local name="$1" needle="$2" haystack="$3"
    if [[ "$haystack" == *"$needle"* ]]; then
        echo "  ✓ $name"
        PASS=$((PASS + 1))
    else
        echo "  ✗ $name (missing: $needle)"
        echo "      output: $haystack"
        FAIL=$((FAIL + 1))
    fi
}

assert_not_contains() {
    local name="$1" needle="$2" haystack="$3"
    if [[ "$haystack" != *"$needle"* ]]; then
        echo "  ✓ $name"
        PASS=$((PASS + 1))
    else
        echo "  ✗ $name (should not contain: $needle)"
        FAIL=$((FAIL + 1))
    fi
}

# -----------------------------------------------------------------------------
echo "Test 1: HIGH-tier @latest emits warning + exit 1"
cat > "$TMP/high.json" <<'JSON'
{
  "mcpServers": {
    "21st-dev-magic": {"command": "npx", "args": ["-y", "@21st-dev/magic@latest"]},
    "memory": {"command": "npx", "args": ["-y", "@modelcontextprotocol/server-memory"]}
  }
}
JSON
out="$("$CHECK" --mcp-json "$TMP/high.json" 2>&1)" && rc=$? || rc=$?
assert_exit "exits 1 on HIGH-tier @latest" 1 "$rc"
assert_contains "warns HIGH-tier" "HIGH-tier" "$out"
assert_contains "names the server" "21st-dev-magic" "$out"
assert_contains "points to matrix" "mcp-version-matrix.md" "$out"

# -----------------------------------------------------------------------------
echo "Test 2: MEDIUM-tier @latest is informational, exit 0"
cat > "$TMP/medium.json" <<'JSON'
{
  "mcpServers": {
    "context7": {"command": "npx", "args": ["-y", "@upstash/context7-mcp@latest"]},
    "tavily": {"command": "sh", "args": ["-c", "exec npx -y tavily-mcp@latest"]}
  }
}
JSON
out="$("$CHECK" --mcp-json "$TMP/medium.json" 2>&1)" && rc=$? || rc=$?
assert_exit "exits 0 on MEDIUM-tier only" 0 "$rc"
assert_contains "informational MEDIUM" "MEDIUM-tier" "$out"
assert_not_contains "no HIGH warning" "HIGH-tier" "$out"

# -----------------------------------------------------------------------------
echo "Test 3: pinned HIGH-tier passes, exit 0"
cat > "$TMP/pinned.json" <<'JSON'
{
  "mcpServers": {
    "21st-dev-magic": {"command": "npx", "args": ["-y", "@21st-dev/magic@0.1.0"]},
    "agentation": {"command": "npx", "args": ["-y", "agentation-mcp@1.2.0"]}
  }
}
JSON
out="$("$CHECK" --mcp-json "$TMP/pinned.json" 2>&1)" && rc=$? || rc=$?
assert_exit "exits 0 when HIGH-tier is pinned" 0 "$rc"
assert_contains "reports OK" "OK" "$out"

# -----------------------------------------------------------------------------
echo "Test 4: disabled HIGH-tier @latest is ignored"
cat > "$TMP/disabled.json" <<'JSON'
{
  "mcpServers": {
    "agentation": {"command": "npx", "args": ["-y", "agentation-mcp"], "disabled": true}
  }
}
JSON
out="$("$CHECK" --mcp-json "$TMP/disabled.json" 2>&1)" && rc=$? || rc=$?
assert_exit "exits 0 when only HIGH-tier entry is disabled" 0 "$rc"
assert_not_contains "no warning for disabled" "agentation" "$out"

# -----------------------------------------------------------------------------
echo "Test 5: local server (node ./server.mjs) is skipped"
cat > "$TMP/local.json" <<'JSON'
{
  "mcpServers": {
    "ork-elicit": {"command": "node", "args": ["plugins/ork/mcp-server/server.mjs"]}
  }
}
JSON
out="$("$CHECK" --mcp-json "$TMP/local.json" 2>&1)" && rc=$? || rc=$?
assert_exit "exits 0 for local-only servers" 0 "$rc"

# -----------------------------------------------------------------------------
echo "Test 6: --json output is parseable + has correct shape"
cat > "$TMP/mixed.json" <<'JSON'
{
  "mcpServers": {
    "21st-dev-magic": {"command": "npx", "args": ["-y", "@21st-dev/magic@latest"]},
    "context7": {"command": "npx", "args": ["-y", "@upstash/context7-mcp@latest"]},
    "memory": {"command": "npx", "args": ["-y", "@modelcontextprotocol/server-memory"]}
  }
}
JSON
out="$("$CHECK" --mcp-json "$TMP/mixed.json" --json 2>&1)" && rc=$? || rc=$?
assert_exit "exits 1 on mixed with HIGH" 1 "$rc"
# Validate JSON parses + check fields
parsed="$(echo "$out" | python3 -c "
import json, sys
d = json.load(sys.stdin)
print(d['status'])
print(','.join(d['high_tier_unpinned']))
print(','.join(d['medium_tier_unpinned']))
")"
status="$(echo "$parsed" | sed -n '1p')"
high="$(echo "$parsed" | sed -n '2p')"
medium="$(echo "$parsed" | sed -n '3p')"
assert_contains "json status=warning" "warning" "$status"
assert_contains "json captures HIGH" "21st-dev-magic" "$high"
assert_contains "json captures MEDIUM" "context7" "$medium"

# -----------------------------------------------------------------------------
echo "Test 7: missing .mcp.json is a clean skip (exit 0)"
out="$("$CHECK" --mcp-json "$TMP/does-not-exist.json" 2>&1)" && rc=$? || rc=$?
assert_exit "exits 0 when .mcp.json absent" 0 "$rc"
assert_contains "skipped message" "skipped" "$out"

# -----------------------------------------------------------------------------
echo ""
echo "Results: $PASS passed, $FAIL failed"
[[ $FAIL -eq 0 ]] && exit 0 || exit 1
